const source = $('Read Source Rows').all();
const existing = $input.all();
const doneByName = new Map();
for (const e of existing) {
  const j = (e && e.json) ? e.json : {};
  const eid = (j['Zoho Account Id'] == null ? '' : j['Zoho Account Id']).toString().trim();
  if (!eid) { continue; }
  doneByName.set(eid, (j['Zoho Account Name'] == null ? '' : j['Zoho Account Name']).toString().trim());
}
const out = [];
for (const s of source) {
  const j = (s && s.json) ? s.json : {};
  const nm = (j['Zoho Account Name'] == null ? '' : j['Zoho Account Name']).toString().trim();
  const sid = (j['Zoho Account Id'] == null ? '' : j['Zoho Account Id']).toString().trim();
  if (!nm || !sid) { continue; }
  const prev = doneByName.get(sid);
  if (prev === undefined || prev !== nm) {
    out.push({ json: { 'Zoho Account Name': nm, 'Zoho Account Id': sid } });
  }
}
return out;

const name = ($json['Zoho Account Name'] == null ? '' : $json['Zoho Account Name']).toString();
const id = ($json['Zoho Account Id'] == null ? '' : $json['Zoho Account Id']).toString();
const system = "You are a brand-identification assistant for Growisto's sales/CRM data.

You are given a single Zoho CRM "account name". This string very often contains the brand PLUS internal project descriptors such as "Website Unification", "Amazon Marketing", "Images work", "Amazon", "SEO", "- Marketing", or trailing punctuation. Your job has two parts:

1. Identify the real, consumer-facing BRAND behind the account name. Strip every project/service descriptor, platform name (amazon, website, seo, etc.), and internal qualifier. Keep a genuine sub-brand if it is itself the brand (e.g. "Tata CLiQ Palette" is a distinct brand from "Tata CLiQ").
2. List the COMMON NAMES - every way real customers, fans, and the public actually refer to that brand: the official name, casual/short forms, spaced AND unspaced variants, and well-known nicknames. Use your real-world knowledge of the brand, not just the literal string.

Rules:
- Output lowercase only.
- The brand's primary name MUST be the first item in common_names.
- Always include obvious spacing/spelling variants (e.g. both "boat lifestyle" and "boatlifestyle").
- NEVER include project descriptors, platform names (amazon, website, seo), or generic filler words.
- If you do not recognise the brand, return your best cleaned name plus only its obvious variants.
- Return ONLY valid JSON - no markdown fences, no commentary - in exactly this shape:
  {"brand": "<clean brand name>", "common_names": ["name1","name2"]}

Examples:

Account name: "boAt Lifestyle - Amazon Marketing"
{"brand": "boAt", "common_names": ["boat","boat lifestyle","boatlifestyle"]}

Account name: "Kaya Website Unification"
{"brand": "Kaya", "common_names": ["kaya","kaya clinic","kaya skin clinic"]}

Account name: "Tata Cliq"
{"brand": "Tata CLiQ", "common_names": ["tata cliq","tatacliq","tatacliq.com"]}

Account name: "Tata CLiQ Palette"
{"brand": "Tata CLiQ Palette", "common_names": ["tata cliq palette","tatacliq palette","cliq palette"]}";
return {
  'Zoho Account Name': name,
  'Zoho Account Id': id,
  claudeRequestBody: {
    model: 'claude-sonnet-4-6',
    max_tokens: 400,
    system: system,
    messages: [{ role: 'user', content: 'Account name: "' + name + '"' }]
  }
};

let text = '';
try { text = $json.content[0].text; } catch (e) { text = ''; }
let names = '';
try {
  const parsed = JSON.parse(text);
  if (parsed && Array.isArray(parsed.common_names)) {
    names = parsed.common_names.map(function (x) { return (x == null ? '' : x).toString().trim(); }).filter(function (x) { return x.length > 0; }).join(',');
  }
} catch (e) {
  names = (text || '').replace(/\s+/g, ' ').trim();
}
return {
  'Zoho Account Name': $('Build Claude Request').item.json['Zoho Account Name'],
  'Zoho Account Id': $('Build Claude Request').item.json['Zoho Account Id'],
  'common names': names
};

const source = $('Read Source Rows').all();
const existing = $('Read Existing Output').all();
const sourceIds = new Set();
for (const s of source) {
  const j = (s && s.json) ? s.json : {};
  const sid = (j['Zoho Account Id'] == null ? '' : j['Zoho Account Id']).toString().trim();
  if (sid) { sourceIds.add(sid); }
}
if (sourceIds.size === 0) { return []; }
const orphans = [];
for (const e of existing) {
  const j = (e && e.json) ? e.json : {};
  const eid = (j['Zoho Account Id'] == null ? '' : j['Zoho Account Id']).toString().trim();
  const rn = j['row_number'];
  if (!eid) { continue; }
  if (typeof rn !== 'number') { continue; }
  if (!sourceIds.has(eid)) {
    orphans.push({ rowNumber: rn, 'Zoho Account Name': (j['Zoho Account Name'] == null ? '' : j['Zoho Account Name']), 'Zoho Account Id': eid });
  }
}
orphans.sort(function (a, b) { return b.rowNumber - a.rowNumber; });
return orphans.map(function (o) { return { json: o }; });
